// ─── Profile Avatar ───────────────────────────────────────────────────────────

function ProfileAvatar({ uri, name }: { uri?: string | null; name?: string }) {
  const AVATAR_SIZE = 38;
  const initials = name ? name.trim().charAt(0).toUpperCase() : '?';

  if (uri) {
    return (
      <Image
        source={{ uri }}
        style={{
          width: AVATAR_SIZE,
          height: AVATAR_SIZE,
          borderRadius: AVATAR_SIZE / 2,
        }}
      />
    );
  }

  return (
    <View
      style={{
        width: AVATAR_SIZE,
        height: AVATAR_SIZE,
        borderRadius: AVATAR_SIZE / 2,
        backgroundColor: '#1A3040',
        alignItems: 'center',
        justifyContent: 'center',
      }}
    >
      <Text style={{ color: INACTIVE, fontSize: 16, fontWeight: '600' }}>
        {initials}
      </Text>
    </View>
  );
}

// ─── Tab icon resolver ────────────────────────────────────────────────────────

function TabIcon({
  routeName,
  color,
  active,
  user,
}: {
  routeName: string;
  color: string;
  active: boolean;
  user: { avatar?: string | null; name?: string } | null;
}) {
  switch (routeName) {
    case 'Dashboard':
      return <HomeIcon color={color} active={active} />;
    case 'Expenses':
      return <AnalysisIcon color={color} active={active} />;
    case 'AI':
      return <AiChatIcon color={color} active={active} />;
    case 'Groups':
      return <GroupsIcon color={color} active={active} />;
    case 'Profile':
      return <ProfileAvatar uri={user?.avatar} name={user?.name} />;
    default:
      return null;
  }
}

// ─── Main Component ───────────────────────────────────────────────────────────

export default function CustomTabBar({ state, navigation }: BottomTabBarProps) {
  const insets = useSafeAreaInsets();
  const { user } = useAuthStore();

  // Measure the inner capsule width so we can calculate pill width per tab
  const [capsuleWidth, setCapsuleWidth] = useState(0);

  // Animated value tracks the active tab index (fractional during animation)
  const pillAnim = useRef(new Animated.Value(state.index)).current;

  useEffect(() => {
    Animated.spring(pillAnim, {
      toValue: state.index,
      useNativeDriver: true,
      tension: 30,  // snappy but not jarring
      friction: 6,  // smooth settling, minimal overshoot
    }).start();
  }, [state.index]);

  const tabCount  = state.routes.length;
  // Subtract capsule horizontal padding (8 each side = 16) for the usable inner width
  const pillWidth = capsuleWidth > 0 ? (capsuleWidth - 16) / tabCount : 0;

  // translateX slides the pill from slot 0 to slot N
  const translateX = pillAnim.interpolate({
    inputRange:  Array.from({ length: tabCount }, (_, i) => i),
    outputRange: Array.from({ length: tabCount }, (_, i) => i * pillWidth),
  });

  // Bottom margin: 24px from spec, plus device safe-area (home indicator)
  const bottomPad = Math.max(2, insets.bottom + 12);

  return (
    <View style={[styles.wrapper, { paddingBottom: bottomPad }]}>
      <View
        style={styles.capsule}
        onLayout={(e) => setCapsuleWidth(e.nativeEvent.layout.width)}
      >
        {/* Animated sliding pill — sits behind the tab icons */}
        {pillWidth > 0 && (
          <Animated.View
            pointerEvents="none"
            style={[
              styles.pill,
              { width: pillWidth, transform: [{ translateX }] },
            ]}
          />
        )}

        {state.routes.map((route, index) => {
          const isFocused = state.index === index;
          const isProfile = route.name === 'Profile';

          // Icons change colour when active; profile pic stays as-is
          const iconColor = isFocused && !isProfile ? ACTIVE : INACTIVE;

          const onPress = () => {
            const event = navigation.emit({
              type: 'tabPress',
              target: route.key,
              canPreventDefault: true,
            });
            if (!isFocused && !event.defaultPrevented) {
              navigation.navigate(route.name as never);
            }
          };

          return (
            <TouchableOpacity
              key={route.key}
              accessibilityRole="button"
              accessibilityState={isFocused ? { selected: true } : {}}
              onPress={onPress}
              activeOpacity={0.85}
              style={styles.tab}
            >
              <TabIcon
                routeName={route.name}
                color={iconColor}
                active={isFocused}
                user={user}
              />
            </TouchableOpacity>
          );
        })}
      </View>
    </View>
  );
}

